-- =====================================================================
-- MODULE: PROGRAMMING REQUESTS MANAGEMENT
-- MODULE: QUẢN LÝ YÊU CẦU LẬP TRÌNH
-- =====================================================================
-- Mapped from source file: KH_CODE.csv
-- Ánh xạ từ file nguồn: KH_CODE.csv
--
-- BUSINESS CONTEXT / BỐI CẢNH NGHIỆP VỤ:
--   This module manages the full lifecycle of internal software development
--   requests — from receiving a customer/support request, through analysis,
--   coding, deployment (upcode), and customer notification.
--
--   Module này quản lý toàn bộ vòng đời của yêu cầu phát triển phần mềm nội bộ
--   — từ khi tiếp nhận yêu cầu từ khách hàng/hỗ trợ, qua phân tích, lập trình,
--   triển khai (upcode), đến thông báo cho khách hàng.
--
-- MASTER WORKFLOW / LUỒNG XỬ LÝ CHÍNH:
--   NEW → ANALYZING → CODING → PENDING_UPCODE → UPCODED → NOTIFIED → CLOSED
--   (CANCELLED có thể xảy ra ở bất kỳ bước nào / can occur at any stage)
--
-- RELATED TABLES / BẢNG LIÊN QUAN:
--   support_requests    — Ticket hỗ trợ nguồn gốc (source support ticket)
--   customers           — Đơn vị khách hàng (customer organization)
--   projects            — Dự án liên quan (related project)
--   products            — Phần mềm liên quan (related software product)
--   internal_users      — Nhân viên nội bộ (staff: analyzer, coder, upcoder...)
--   customer_personnel  — Đầu mối liên hệ phía khách hàng (customer contact)
--   support_service_groups — Nhóm kỹ thuật xử lý (L2, L3, OS, HIS...)
--
-- VERSION HISTORY / LỊCH SỬ PHIÊN BẢN:
--   V7  — Initial structure / Cấu trúc ban đầu
--   V8  — Added ticket_code, receiver_id, reporter_contact_id, reference_request_id
--   V10 — Added hours_estimated, hours_spent to worklogs; optimized indexes
--   V11 — Covering indexes with deleted_at for soft-delete performance
--   V12 — Full bilingual AI-vibe comments; added requested_date
-- =====================================================================

-- Bảng 40: Quản lý Yêu cầu Lập trình & Sub-tasks
-- =====================================================================
-- TASK HIERARCHY / CẤU TRÚC CÂY TASK (tối đa 3 cấp / max 3 levels):
--
--   depth=0 (Root Task / Task gốc):
--     Yêu cầu chính từ khách hàng hoặc nội bộ. parent_id PHẢI là NULL.
--     The main request from customer or internal team. parent_id MUST be NULL.
--
--   depth=1 (Sub-task / Task con):
--     Công việc con chia nhỏ từ task gốc (VD: phân tích một màn hình).
--     Child work item broken down from root (e.g. analyzing one screen).
--     parent_id PHẢI trỏ đến một record depth=0.
--
--   depth=2 (Leaf Task / Task lá):
--     Đơn vị công việc nhỏ nhất, không thể chia nhỏ hơn.
--     The smallest unit of work, cannot be broken down further.
--     parent_id PHẢI trỏ đến một record depth=1.
--
-- ENFORCEMENT: chk_prog_depth + chk_depth_parent_consistency
-- =====================================================================

CREATE TABLE IF NOT EXISTS `programming_requests` (
    `id`   bigint unsigned NOT NULL AUTO_INCREMENT
           COMMENT 'Auto-increment primary key. Khóa chính tự tăng.',

    `uuid` char(36) UNIQUE NOT NULL DEFAULT (UUID())
           COMMENT 'Globally unique identifier for API exposure. '
                   'KHÔNG dùng id trực tiếp trên API để tránh lộ thông tin tuần tự. '
                   'Use this instead of id in public-facing APIs to prevent enumeration.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Identity & External Links]
-- [NHÓM: Định danh & Liên kết ngoại bộ]
-- ----------------------------------------------------------------
`req_code` varchar(50) UNIQUE NOT NULL COMMENT '[PK-like | Required] Mã yêu cầu dạng đọc được. ' 'Human-readable unique request code. ' 'Format: REQDEV + 6 số tăng dần — VD/e.g.: REQDEV000123. ' 'Generated by system and immutable after creation.',
`req_name` varchar(255) NOT NULL COMMENT '[Required] Tên ngắn của yêu cầu hoặc sub-task. ' 'Short title/summary of the request or sub-task. ' 'Hiển thị trên danh sách, dashboard, email thông báo. ' 'Displayed on lists, dashboards, and notification emails.',
`ticket_code` varchar(50) DEFAULT NULL COMMENT 'Mã Jira (VD: IT360-1234) hoặc mã Bitbucket PR liên quan. ' 'Jira issue code (e.g. IT360-1234) or Bitbucket PR identifier. ' 'NULL nếu không dùng Jira/Bitbucket. NULL if not tracked externally.',
`task_link` text DEFAULT NULL COMMENT 'URL truy cập trực tiếp vào Jira issue hoặc Bitbucket PR. ' 'Direct URL to the Jira issue or Bitbucket PR for quick access. ' 'Hiển thị dưới dạng hyperlink trong giao diện. ' 'Rendered as a clickable hyperlink in the UI.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Hierarchy & Relationships]
-- [NHÓM: Cây phân cấp & Quan hệ task]
-- ----------------------------------------------------------------
`parent_id` bigint unsigned DEFAULT NULL COMMENT '[FK → programming_requests.id | ON DELETE RESTRICT] ' 'NULL = task gốc (depth=0). Non-NULL = task con/lá. ' 'NULL means root task (depth=0). Non-NULL means sub/leaf task. ' 'KHÔNG THỂ xóa task cha khi còn task con. ' 'Parent cannot be deleted while children exist (RESTRICT).',
`depth` tinyint NOT NULL DEFAULT 0 COMMENT '[0-2 | Required] Cấp độ trong cây task. ' 'Tree depth level. 0=root/gốc, 1=sub-task/con, 2=leaf/lá. ' 'PHẢI đồng bộ với parent_id khi tạo/cập nhật task. ' 'MUST stay in sync with parent_id. Enforced: chk_depth_parent_consistency.',
`reference_request_id` bigint unsigned DEFAULT NULL COMMENT '[FK → programming_requests.id | ON DELETE SET NULL] ' 'Task LIÊN QUAN theo chiều ngang (Relates To) — ' 'KHÁC với parent_id (quan hệ cha-con theo chiều dọc). ' 'Horizontally related task (Relates To) — ' 'DIFFERENT from parent_id (vertical parent-child). ' 'VD: Task refactor liên quan đến task feature trước đó. ' 'E.g. a refactor task that relates to a prior feature task.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Classification & Origin]
-- [NHÓM: Phân loại & Nguồn gốc yêu cầu]
-- ----------------------------------------------------------------
`source_type` enum(
    'DIRECT',
    'FROM_SUPPORT'
) NOT NULL DEFAULT 'DIRECT' COMMENT '[Enum | Required] Nguồn gốc phát sinh yêu cầu lập trình. ' 'Origin/trigger of this programming request. ' 'DIRECT       = Yêu cầu nội bộ, không qua ticket hỗ trợ. ' 'Internal request, not linked to any support ticket. ' 'support_request_id PHẢI NULL. ' 'FROM_SUPPORT = Phát sinh từ ticket hỗ trợ. ' 'Originated from a support ticket. ' 'support_request_id PHẢI có giá trị / MUST NOT be NULL. ' 'Enforced by: chk_source_consistency.',
`req_type` enum(
    'FEATURE',
    'BUG',
    'OPTIMIZE',
    'REPORT',
    'OTHER'
) NOT NULL DEFAULT 'FEATURE' COMMENT '[Enum | Required] Loại công việc lập trình. ' 'Category of programming work. ' 'FEATURE  = Tính năng mới / New feature development. ' 'BUG      = Sửa lỗi / Bug fix — thường bỏ qua pha Phân Tích. ' 'Bug fix — typically skips the ANALYZING phase. ' 'OPTIMIZE = Tối ưu hiệu năng/code / Performance or code optimization. ' 'REPORT   = Làm báo cáo/thống kê / Report or data export. ' 'OTHER    = Loại khác / Other work types.',
`service_group_id` bigint unsigned DEFAULT NULL COMMENT '[FK → support_service_groups.id | ON DELETE SET NULL] ' 'Nhóm kỹ thuật nội bộ thực hiện yêu cầu này. ' 'Internal technical team responsible for this request. ' 'VD / e.g.: HIS L3, Văn bản L2, OS Team, Database Team. ' 'NULL nếu chưa phân công nhóm / NULL if no team assigned yet.',
`support_request_id` bigint unsigned DEFAULT NULL COMMENT '[FK → support_requests.id | ON DELETE RESTRICT] ' 'Ticket hỗ trợ nguồn gốc — BẮT BUỘC khi source_type là FROM_SUPPORT. ' 'Source support ticket — REQUIRED when source_type is FROM_SUPPORT. ' 'PHẢI NULL khi source_type = DIRECT. ' 'MUST BE NULL when source_type = DIRECT. ' 'RESTRICT: Không thể xóa support ticket khi đang có coding request tham chiếu. ' 'Cannot delete a support ticket that has linked coding requests.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Priority & Progress]
-- [NHÓM: Độ ưu tiên & Tiến độ]
-- ----------------------------------------------------------------
`priority` tinyint DEFAULT 3 COMMENT '[1-4 | Default: 3] Độ ưu tiên xử lý. Càng nhỏ càng ưu tiên cao. ' 'Processing priority. Lower number = higher priority. ' '1 = Thấp. ' '2 = Trung bình. ' '3 = Cao (mặc định). ' '4 = Khẩn cấp. ' 'Dùng để sắp xếp danh sách task trên dashboard. ' 'Used for dashboard task sorting. Enforced: chk_prog_priority.',
`overall_progress` tinyint DEFAULT 0 COMMENT '[0-100 | Default: 0] Phần trăm hoàn thành tổng thể của toàn task. ' 'Overall completion percentage of the entire request. ' 'Nên tự động tính từ trung bình có trọng số của analyze_progress + code_progress tại tầng ứng dụng. ' 'Should be auto-calculated from weighted average of phase progress fields at app layer. ' 'Enforced: chk_overall_progress (0-100).',
`status` enum(
    'NEW',
    'ANALYZING',
    'CODING',
    'PENDING_UPCODE',
    'UPCODED',
    'NOTIFIED',
    'CLOSED',
    'CANCELLED'
) NOT NULL DEFAULT 'NEW' COMMENT '[Enum | Required | Default: NEW] Trạng thái tổng thể của yêu cầu. ' 'Master lifecycle status of the request. Drives UI workflow and permissions. ' 'NEW          = Mới tạo, chưa bắt đầu xử lý / Newly created, not yet started. ' 'ANALYZING    = Đang trong giai đoạn phân tích yêu cầu / Under analysis. ' 'CODING       = Đang lập trình / Under active development. ' 'PENDING_UPCODE = Code xong, chờ triển khai lên môi trường production / ' 'Coding complete, awaiting production deployment. ' 'UPCODED      = Đã triển khai thành công / Successfully deployed to production. ' 'NOTIFIED     = Đã thông báo cho khách hàng / Customer has been notified. ' 'CLOSED       = Đã đóng, hoàn tất toàn bộ quy trình / Fully completed and closed. ' 'CANCELLED    = Huỷ bỏ, không thực hiện / Cancelled, will not be executed.',
`description` text COMMENT 'Mô tả chi tiết yêu cầu, bối cảnh nghiệp vụ, ghi chú kỹ thuật. ' 'Detailed description, business context, and technical notes. ' 'Hỗ trợ định dạng Markdown nếu UI cho phép / Supports Markdown if UI renders it.',
`doc_link` text COMMENT 'URL đến biên bản họp, tài liệu đặc tả, hoặc văn bản yêu cầu chính thức. ' 'URL to meeting minutes, specification document, or official request document. ' 'Khác với task_link (Jira/Bitbucket) — đây là tài liệu nghiệp vụ. ' 'Different from task_link (Jira/Bitbucket) — this is a business document.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Customer, Project & Reception]
-- [NHÓM: Khách hàng, Dự án & Thông tin tiếp nhận]
-- ----------------------------------------------------------------
`customer_id` bigint unsigned DEFAULT NULL COMMENT '[FK → customers.id | ON DELETE RESTRICT] ' 'Đơn vị khách hàng/tổ chức có yêu cầu. ' 'Customer organization that submitted this request. ' 'RESTRICT: Không thể xóa khách hàng khi còn yêu cầu lập trình. ' 'Cannot delete a customer that has linked programming requests.',
`requested_date` date NOT NULL DEFAULT(CURRENT_DATE) COMMENT '[Required | Default: hôm nay / today] ' 'Ngày khách hàng/bộ phận gửi yêu cầu — là ngày NGHIỆP VỤ, ' 'KHÁC với created_at là timestamp hệ thống khi nhập liệu. ' 'Date the customer/department submitted the request — this is the BUSINESS date, ' 'DIFFERENT from created_at which is the system timestamp when data was entered. ' 'VD: KH gửi email ngày 01/03, nhập hệ thống ngày 03/03 → requested_date=01/03. ' 'E.g. Customer emailed on Mar 1, entered on Mar 3 → requested_date=Mar 1. ' 'Dùng cho báo cáo "Số yêu cầu nhận trong tháng". ' 'Used in "Requests received per month" reports.',
`reporter_name` varchar(100) DEFAULT NULL COMMENT 'Tên người gửi/yêu cầu — ghi tự do, dùng làm fallback. ' 'Free-text name of the person who submitted the request — used as fallback. ' 'Ưu tiên dùng reporter_contact_id nếu người này có trong DB. ' 'Prefer reporter_contact_id if this person exists in customer_personnel.',
`reporter_contact_id` bigint unsigned DEFAULT NULL COMMENT '[FK → customer_personnel.id | ON DELETE SET NULL] ' 'Đầu mối liên hệ phía khách hàng gửi yêu cầu — phiên bản chuẩn hóa DB. ' 'Normalized DB reference to the customer contact who submitted the request. ' 'Khi có giá trị này, ưu tiên hơn reporter_name (free text). ' 'When populated, takes precedence over reporter_name (free text). ' 'SET NULL khi nhân sự khách hàng bị xóa / SET NULL if contact is deleted.',
`receiver_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên nội bộ tiếp nhận và ghi nhận yêu cầu vào hệ thống. ' 'Internal staff who received and logged this request into the system. ' 'Đây là người TIẾP NHẬN BAN ĐẦU, có thể khác với analyzer_id hoặc coder_id. ' 'This is the INITIAL RECEIVER, may differ from analyzer_id or coder_id. ' 'Tương tự receiver_user_id trong support_requests. ' 'Analogous to receiver_user_id in support_requests.',
`project_id` bigint unsigned DEFAULT NULL COMMENT '[FK → projects.id | ON DELETE SET NULL] ' 'Dự án mà yêu cầu lập trình này thuộc về. ' 'Project this programming request belongs to. ' 'VD / e.g.: HIS, Văn bản 130, Kế toán tập trung. ' 'NULL nếu không gắn với dự án cụ thể / NULL if not project-specific.',
`product_id` bigint unsigned DEFAULT NULL COMMENT '[FK → products.id | ON DELETE SET NULL] ' 'Phần mềm/module cụ thể được yêu cầu thay đổi. ' 'Specific software product or module to be modified. ' 'VD / e.g.: HIS v3.2, Phần mềm Văn bản, App Mobile.',
`project_item_id` bigint unsigned DEFAULT NULL COMMENT '[FK → project_items.id | ON DELETE SET NULL] ' 'Hạng mục dự án cụ thể mà yêu cầu này thuộc về. ' 'Specific project line item this request falls under. ' 'Dùng cho phân bổ chi phí và theo dõi ngân sách dự án. ' 'Used for cost allocation and project budget tracking.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: ANALYZE Phase — Giai đoạn Phân tích]
-- ----------------------------------------------------------------
-- BUSINESS RULE: Pha này có thể BỎ QUA đối với BUG hoặc OPTIMIZE đơn giản.
-- This phase can be SKIPPED for simple BUG fixes or OPTIMIZE tasks.
-- Khi bỏ qua: để tất cả analyze_* = NULL. When skipped: leave all analyze_* = NULL.
--
-- DATE CHRONOLOGY / THỨ TỰ NGÀY:
--   analyze_start_date ≤ analyze_end_date ≤ analyze_extend_date
--   Enforced by: chk_analyze_dates, chk_analyze_extend, chk_analyze_extend_requires_end
-- ----------------------------------------------------------------
`analyze_estimated_hours` decimal(6, 2) DEFAULT NULL COMMENT 'Tổng số giờ dự kiến cho toàn bộ giai đoạn Phân tích. ' 'Total estimated hours for the entire Analysis phase. ' 'Đây là ước tính tổng quan ở cấp task — chi tiết từng ngày ghi trong worklogs. ' 'This is a high-level task estimate — daily details logged in worklogs table.',
`analyze_start_date` date DEFAULT NULL COMMENT 'Ngày BẮT ĐẦU thực tế của giai đoạn Phân tích. ' 'Actual START date of the Analysis phase. ' 'NULL nghĩa là pha chưa bắt đầu / NULL means phase not yet started.',
`analyze_end_date` date DEFAULT NULL COMMENT 'Ngày KẾT THÚC DỰ KIẾN (deadline) của giai đoạn Phân tích. ' 'PLANNED END date (deadline) for the Analysis phase. ' 'Phải >= analyze_start_date / Must be >= analyze_start_date. ' 'analyze_extend_date phải >= trường này nếu có gia hạn. ' 'analyze_extend_date must be >= this field if extended.',
`analyze_extend_date` date DEFAULT NULL COMMENT 'Ngày gia hạn mới cho Phân tích khi không kịp analyze_end_date. ' 'New extended deadline for Analysis when original deadline is missed. ' 'Phải >= analyze_end_date và analyze_end_date phải có giá trị trước. ' 'Must be >= analyze_end_date, and analyze_end_date must exist first. ' 'Enforced: chk_analyze_extend + chk_analyze_extend_requires_end.',
`analyzer_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên chịu trách nhiệm chính trong giai đoạn Phân tích yêu cầu. ' 'Internal staff responsible for the Analysis phase. ' 'Thường là BA hoặc Tech Lead. Typically a Business Analyst or Tech Lead. ' 'SET NULL khi nhân viên bị xóa khỏi hệ thống / SET NULL if user is deleted.',
`analyze_progress` tinyint DEFAULT 0 COMMENT '[0-100 | Default: 0] Phần trăm hoàn thành của giai đoạn Phân tích. ' 'Completion percentage of the Analysis phase. ' '100 = Phân tích hoàn tất, sẵn sàng chuyển sang Lập trình. ' '100 = Analysis complete, ready to transition to Coding phase. ' 'Enforced: chk_analyze_progress.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: CODE Phase — Giai đoạn Lập trình]
-- ----------------------------------------------------------------
-- DATE CHRONOLOGY / THỨ TỰ NGÀY:
--   code_start_date  ≥ analyze_end_date  (nếu có phân tích / if analysis was done)
--   code_start_date  ≤ code_end_date
--   code_end_date    ≤ code_extend_date   (nếu có gia hạn / if extended)
--   code_start_date  ≤ code_actual_date
--   code_actual_date ≤ upcode_date         (phase tiếp theo)
-- Enforced by: chk_code_dates, chk_code_extend, chk_code_actual_date,
--              chk_phase_order_code_after_analyze, chk_code_extend_requires_end
-- ----------------------------------------------------------------
`code_estimated_hours` decimal(6, 2) DEFAULT NULL COMMENT 'Tổng số giờ dự kiến cho toàn bộ giai đoạn Lập trình. ' 'Total estimated hours for the entire Coding phase. ' 'Đây là ước tính tổng quan ở cấp task — chi tiết từng ngày ghi trong worklogs. ' 'High-level task estimate — daily details logged in worklogs table.',
`code_start_date` date DEFAULT NULL COMMENT 'Ngày BẮT ĐẦU lập trình thực tế. ' 'Actual START date of the Coding phase. ' 'Phải >= analyze_end_date nếu đã có giai đoạn phân tích. ' 'Must be >= analyze_end_date if analysis phase was completed. ' 'Enforced: chk_phase_order_code_after_analyze.',
`code_end_date` date DEFAULT NULL COMMENT 'Ngày KẾT THÚC DỰ KIẾN (deadline) của giai đoạn Lập trình. ' 'PLANNED END date (deadline) for the Coding phase. ' 'Phải >= code_start_date / Must be >= code_start_date.',
`code_extend_date` date DEFAULT NULL COMMENT 'Ngày gia hạn mới cho Lập trình khi không kịp code_end_date. ' 'New extended deadline for Coding when original deadline is missed. ' 'Phải >= code_end_date, và code_end_date phải có giá trị trước. ' 'Must be >= code_end_date, and code_end_date must exist first. ' 'Enforced: chk_code_extend + chk_code_extend_requires_end.',
`code_actual_date` date DEFAULT NULL COMMENT 'Ngày HOÀN THÀNH LẬP TRÌNH THỰC TẾ (ngày coder bàn giao code). ' 'Actual date coding was COMPLETED (handoff date from coder). ' 'Khi điền trường này, hệ thống nên tự chuyển status → PENDING_UPCODE. ' 'When this field is set, system should auto-transition status → PENDING_UPCODE. ' 'Phải >= code_start_date / Must be >= code_start_date.',
`coder_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Lập trình viên được giao thực hiện yêu cầu này. ' 'Developer assigned to implement this request. ' 'SET NULL khi nhân viên bị xóa / SET NULL if user is deleted.',
`code_progress` tinyint DEFAULT 0 COMMENT '[0-100 | Default: 0] Phần trăm hoàn thành của giai đoạn Lập trình. ' 'Completion percentage of the Coding phase. ' '100 = Code xong, sẵn sàng upcode / 100 = Coding done, ready to deploy. ' 'Enforced: chk_code_progress.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: UPCODE Phase — Giai đoạn Triển khai]
-- ----------------------------------------------------------------
-- BUSINESS TERM: "Upcode" = hành động đẩy code lên môi trường production/staging.
-- "Upcode" = the act of deploying code to production or staging environment.
--
-- DATE RULE: upcode_date ≥ code_actual_date
-- Enforced by: chk_phase_order_upcode_after_code
-- ----------------------------------------------------------------
`upcode_status` enum(
    'PENDING',
    'PROCESSING',
    'SUCCESS',
    'FAILED'
) DEFAULT NULL COMMENT '[Enum] Trạng thái triển khai code lên môi trường production. ' 'Deployment status to production environment. ' 'NULL      = Pha chưa bắt đầu / Phase not yet started. ' 'PENDING   = Chờ triển khai, đã có lịch / Scheduled, waiting to deploy. ' 'PROCESSING= Đang triển khai / Deployment in progress. ' 'SUCCESS   = Triển khai thành công / Deployed successfully. ' 'FAILED    = Triển khai thất bại, cần rollback hoặc thử lại. ' 'Deployment failed, needs rollback or retry.',
`upcode_date` date DEFAULT NULL COMMENT 'Ngày TRIỂN KHAI THỰC TẾ lên production. ' 'Actual date the code was deployed to production. ' 'Phải >= code_actual_date / Must be >= code_actual_date. ' 'Enforced: chk_phase_order_upcode_after_code.',
`upcoder_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên thực hiện triển khai code (upcode) lên production. ' 'Staff member who executed the production deployment. ' 'Thường là DevOps hoặc Tech Lead / Usually DevOps or Tech Lead.',

-- ----------------------------------------------------------------
-- [FIELD GROUP: NOTIFY Phase — Giai đoạn Thông báo]
-- ----------------------------------------------------------------
-- BUSINESS RULE: Sau khi upcode thành công, phải thông báo cho khách hàng hoặc
-- bộ phận liên quan. After successful deployment, notify customer or related department.
--
-- MUTUAL EXCLUSIVITY: notified_internal_id XOR notified_customer_id
--   (chỉ một trong hai / only one of the two can be set)
--   Enforced by: chk_noti_recipient_exclusive
--
-- DATE RULE: noti_date ≥ upcode_date
-- Enforced by: chk_phase_order_noti_after_upcode
-- ----------------------------------------------------------------
`noti_status` enum(
    'PENDING',
    'NOTIFIED',
    'FAILED'
) DEFAULT NULL COMMENT '[Enum] Trạng thái thông báo sau khi triển khai. ' 'Notification status after deployment. ' 'NULL     = Pha chưa bắt đầu / Phase not yet started. ' 'PENDING  = Chưa gửi thông báo / Notification not yet sent. ' 'NOTIFIED = Đã thông báo thành công / Notification sent successfully. ' 'FAILED   = Gửi thông báo thất bại (email lỗi, không liên lạc được...). ' 'Notification failed (email error, unreachable contact, etc.).',
`noti_date` date DEFAULT NULL COMMENT 'Ngày thực tế gửi thông báo cho khách hàng/nội bộ. ' 'Actual date the notification was sent to customer or internal recipient. ' 'Phải >= upcode_date / Must be >= upcode_date. ' 'Enforced: chk_phase_order_noti_after_upcode.',
`notifier_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên thực hiện gửi thông báo. ' 'Internal staff who sent the notification. ' 'Thường là người tiếp nhận (receiver_id) hoặc PM. ' 'Usually the initial receiver or project manager.',
`notified_internal_id` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên nội bộ NHẬN thông báo (nếu thông báo nội bộ). ' 'Internal staff RECIPIENT of the notification (if internal notification). ' 'KHÔNG ĐƯỢC đồng thời có giá trị cùng notified_customer_id. ' 'MUTUALLY EXCLUSIVE with notified_customer_id — only one can be set. ' 'Enforced: chk_noti_recipient_exclusive.',
`notified_customer_id` bigint unsigned DEFAULT NULL COMMENT '[FK → customer_personnel.id | ON DELETE SET NULL] ' 'Đầu mối khách hàng NHẬN thông báo (nếu thông báo ra ngoài). ' 'Customer contact RECIPIENT of the notification (if external). ' 'KHÔNG ĐƯỢC đồng thời có giá trị cùng notified_internal_id. ' 'MUTUALLY EXCLUSIVE with notified_internal_id — only one can be set. ' 'Enforced: chk_noti_recipient_exclusive.',
`noti_doc_link` text COMMENT 'URL đến biên bản bàn giao, email xác nhận, hoặc tài liệu thông báo. ' 'URL to handoff memo, confirmation email, or notification document.',

-- ----------------------------------------------------------------
-- [AUDIT LOG — Nhật ký hệ thống]
-- ----------------------------------------------------------------
`created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Timestamp khi bản ghi được tạo trong DB (tự động). ' 'DB record creation timestamp (auto-set). ' 'KHÁC với requested_date là ngày nghiệp vụ tiếp nhận yêu cầu. ' 'DIFFERENT from requested_date which is the business receipt date.',
`created_by` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên tạo bản ghi này trong hệ thống. ' 'Internal user who created this record in the system.',
`updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT 'Timestamp cập nhật cuối (tự động). NULL nếu chưa từng sửa. ' 'Last update timestamp (auto-set on UPDATE). NULL if never modified.',
`updated_by` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên thực hiện cập nhật cuối. NULL nếu chưa từng sửa. ' 'Internal user who last modified this record. NULL if never modified.',
`deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft Delete timestamp. NULL = bản ghi đang active. ' 'Soft Delete timestamp. NULL = record is active. ' 'CẢNH BÁO: Luôn thêm WHERE deleted_at IS NULL trong mọi query đọc dữ liệu. ' 'WARNING: Always add WHERE deleted_at IS NULL in all read queries. ' 'Hỗ trợ khôi phục dữ liệu và audit trail. ' 'Supports data recovery and audit trail.',
PRIMARY KEY (`id`),

-- ----------------------------------------------------------------
-- INDEXES — Chỉ mục tối ưu truy vấn
-- ----------------------------------------------------------------
INDEX `idx_prog_req_code` (`req_code`) COMMENT 'Tìm kiếm nhanh theo mã yêu cầu / Quick lookup by request code',
INDEX `idx_prog_req_parent` (`parent_id`) COMMENT 'Tải danh sách task con của một task cha / Load children of a parent task',
INDEX `idx_prog_req_dashboard` (`status`, `priority`) COMMENT 'Dashboard: lọc task theo trạng thái và sắp xếp theo độ ưu tiên / ' 'Filter by status and sort by priority on dashboard',
INDEX `idx_prog_req_dev_tasks` (`coder_id`, `status`) COMMENT 'Màn hình "Việc của tôi" cho Lập trình viên / ' 'My tasks screen for developers',
INDEX `idx_prog_req_analyzer_tasks` (`analyzer_id`, `status`) COMMENT 'Màn hình "Việc của tôi" cho người Phân tích / ' 'My tasks screen for analysts',
INDEX `idx_prog_req_upcoder` (`upcoder_id`, `upcode_status`) COMMENT 'Danh sách task chờ/đang triển khai của một upcoder / ' 'Pending/processing deploy tasks for a specific upcoder',
INDEX `idx_prog_req_notifier` (`notifier_id`, `noti_status`) COMMENT 'Danh sách task chờ thông báo của một nhân viên / ' 'Notification tasks assigned to a specific staff',
INDEX `idx_prog_req_customer_proj` (`customer_id`, `project_id`) COMMENT 'Lọc task theo khách hàng và dự án / ' 'Filter tasks by customer and project combination',
INDEX `idx_prog_req_type` (`req_type`) COMMENT 'Báo cáo phân loại loại yêu cầu / Report by request type',
INDEX `idx_prog_req_support` (`support_request_id`) COMMENT 'FK support: JOIN với support_requests / ' 'FK index for JOIN with support_requests',
INDEX `idx_prog_ticket_code` (`ticket_code`) COMMENT 'Tìm kiếm theo mã Jira/Bitbucket PR / ' 'Lookup by Jira issue or Bitbucket PR code',
INDEX `idx_prog_ref_req` (`reference_request_id`) COMMENT 'FK index cho quan hệ ngang (Relates To) / ' 'FK index for horizontal relationship (Relates To)',
INDEX `idx_prog_receiver` (`receiver_id`) COMMENT 'Báo cáo task theo người tiếp nhận / ' 'Report tasks by initial receiver',
INDEX `idx_prog_reporter_contact` (`reporter_contact_id`) COMMENT 'Tìm yêu cầu theo đầu mối khách hàng / ' 'Find requests by customer contact',
INDEX `idx_prog_req_requested_date` (`requested_date`, `status`) COMMENT 'Báo cáo "Số yêu cầu nhận trong tháng" theo ngày nghiệp vụ / ' 'Monthly received request report using business date',
INDEX `idx_prog_req_deleted_at` (`deleted_at`, `status`) COMMENT 'Tối ưu filter WHERE deleted_at IS NULL khi liệt kê task active. ' 'Optimizes WHERE deleted_at IS NULL filter for listing active tasks.',

-- ----------------------------------------------------------------
-- CHECK CONSTRAINTS — Ràng buộc dữ liệu
-- ----------------------------------------------------------------

-- Range constraints
CONSTRAINT `chk_prog_priority` CHECK (`priority` BETWEEN 1 AND 4),
CONSTRAINT `chk_prog_req_code_format` CHECK (`req_code` REGEXP '^REQDEV[0-9]{6}$'),
CONSTRAINT `chk_prog_depth` CHECK (`depth` BETWEEN 0 AND 2),
CONSTRAINT `chk_overall_progress` CHECK (
    `overall_progress` BETWEEN 0 AND 100
),
CONSTRAINT `chk_analyze_progress` CHECK (
    `analyze_progress` BETWEEN 0 AND 100
),
CONSTRAINT `chk_code_progress` CHECK (
    `code_progress` BETWEEN 0 AND 100
),

-- Date ordering within each phase
CONSTRAINT `chk_analyze_dates` CHECK (
    `analyze_end_date` IS NULL
    OR `analyze_start_date` IS NULL
    OR `analyze_end_date` >= `analyze_start_date`
),
CONSTRAINT `chk_code_dates` CHECK (
    `code_end_date` IS NULL
    OR `code_start_date` IS NULL
    OR `code_end_date` >= `code_start_date`
),
CONSTRAINT `chk_code_actual_date` CHECK (
    `code_actual_date` IS NULL
    OR `code_start_date` IS NULL
    OR `code_actual_date` >= `code_start_date`
),

-- Business rule: source_type controls support_request_id requirement
CONSTRAINT `chk_source_consistency` CHECK (
    (
        `source_type` = 'DIRECT'
        AND `support_request_id` IS NULL
    )
    OR (
        `source_type` = 'FROM_SUPPORT'
        AND `support_request_id` IS NOT NULL
    )
),

-- Business rule: depth must match parent_id presence
CONSTRAINT `chk_depth_parent_consistency` CHECK (
    (
        `parent_id` IS NULL
        AND `depth` = 0
    )
    OR (
        `parent_id` IS NOT NULL
        AND `depth` > 0
    )
),

-- Prevent self-referencing (would create infinite loops)
CONSTRAINT `chk_prog_parent_not_self` CHECK (
    `parent_id` IS NULL
    OR `parent_id` != `id`
),
CONSTRAINT `chk_prog_ref_not_self` CHECK (
    `reference_request_id` IS NULL
    OR `reference_request_id` != `id`
),

-- Notification recipient mutual exclusivity
CONSTRAINT `chk_noti_recipient_exclusive` CHECK (
    `notified_internal_id` IS NULL
    OR `notified_customer_id` IS NULL
),

-- Extend date requires end date to exist first
CONSTRAINT `chk_analyze_extend_requires_end` CHECK (
    `analyze_extend_date` IS NULL
    OR `analyze_end_date` IS NOT NULL
),
CONSTRAINT `chk_code_extend_requires_end` CHECK (
    `code_extend_date` IS NULL
    OR `code_end_date` IS NOT NULL
),

-- Extend date must be after original end date
CONSTRAINT `chk_analyze_extend` CHECK (
    `analyze_extend_date` IS NULL
    OR `analyze_end_date` IS NULL
    OR `analyze_extend_date` >= `analyze_end_date`
),
CONSTRAINT `chk_code_extend` CHECK (
    `code_extend_date` IS NULL
    OR `code_end_date` IS NULL
    OR `code_extend_date` >= `code_end_date`
),

-- Cross-phase chronological ordering
-- Note: IS NULL in conditions allows skipping phases (e.g. BUG skips ANALYZE)
CONSTRAINT `chk_phase_order_code_after_analyze` CHECK (
    `code_start_date` IS NULL
    OR `analyze_end_date` IS NULL
    OR `code_start_date` >= `analyze_end_date`
),
CONSTRAINT `chk_phase_order_upcode_after_code` CHECK (
    `upcode_date` IS NULL
    OR `code_actual_date` IS NULL
    OR `upcode_date` >= `code_actual_date`
),
CONSTRAINT `chk_phase_order_noti_after_upcode` CHECK (
    `noti_date` IS NULL
    OR `upcode_date` IS NULL
    OR `noti_date` >= `upcode_date`
),

-- ----------------------------------------------------------------
-- FOREIGN KEYS — Ràng buộc khóa ngoại
-- ----------------------------------------------------------------
CONSTRAINT `fk_prog_parent`
        FOREIGN KEY (`parent_id`) REFERENCES `programming_requests`(`id`)
        ON DELETE RESTRICT,      -- Không xóa task cha khi còn task con / Cannot delete parent with children

    CONSTRAINT `fk_prog_ref_req`
        FOREIGN KEY (`reference_request_id`) REFERENCES `programming_requests`(`id`)
        ON DELETE SET NULL,      -- Xóa task liên quan thì set NULL, không ảnh hưởng task hiện tại

    CONSTRAINT `fk_prog_support`
        FOREIGN KEY (`support_request_id`) REFERENCES `support_requests`(`id`)
        ON DELETE RESTRICT,      -- Không xóa support ticket khi còn coding request tham chiếu

    CONSTRAINT `fk_prog_service_group`
        FOREIGN KEY (`service_group_id`) REFERENCES `support_service_groups`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_customer`
        FOREIGN KEY (`customer_id`) REFERENCES `customers`(`id`)
        ON DELETE RESTRICT,      -- Không xóa khách hàng khi còn yêu cầu lập trình

    CONSTRAINT `fk_prog_reporter_contact`
        FOREIGN KEY (`reporter_contact_id`) REFERENCES `customer_personnel`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_receiver`
        FOREIGN KEY (`receiver_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_project`
        FOREIGN KEY (`project_id`) REFERENCES `projects`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_product`
        FOREIGN KEY (`product_id`) REFERENCES `products`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_proj_item`
        FOREIGN KEY (`project_item_id`) REFERENCES `project_items`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_analyzer`
        FOREIGN KEY (`analyzer_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_coder`
        FOREIGN KEY (`coder_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_upcoder`
        FOREIGN KEY (`upcoder_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_notifier`
        FOREIGN KEY (`notifier_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_noti_internal`
        FOREIGN KEY (`notified_internal_id`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_noti_customer`
        FOREIGN KEY (`notified_customer_id`) REFERENCES `customer_personnel`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_cb`
        FOREIGN KEY (`created_by`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL,

    CONSTRAINT `fk_prog_ub`
        FOREIGN KEY (`updated_by`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL

) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Bảng 40: Quản lý Yêu cầu Lập trình & Sub-tasks | '
          'Manages programming request lifecycle from receipt to customer notification';

-- =====================================================================
-- Bảng 41: Nhật ký Công việc (Timesheet) cho Yêu cầu Lập trình
-- =====================================================================
-- PURPOSE / MỤC ĐÍCH:
--   Ghi lại chi tiết từng phiên làm việc của nhân viên theo từng ngày.
--   Records detailed work sessions per staff member per day.
--   Phục vụ báo cáo Timesheet, so sánh Estimate vs Actual hours.
--   Supports Timesheet reporting and Estimate vs Actual hour comparison.
--
-- KEY BUSINESS RULES / QUY TẮC NGHIỆP VỤ QUAN TRỌNG:
--   1. logged_date <= CURRENT_DATE — không được log giờ tương lai.
--      Cannot log hours for future dates. Enforce at backend/API layer.
--   2. Mỗi worklog gắn với một phase cụ thể để báo cáo theo giai đoạn.
--      Each log links to a specific phase for phase-level reporting.
--   3. Soft Delete: LUÔN filter WHERE deleted_at IS NULL khi aggregate.
--      ALWAYS filter WHERE deleted_at IS NULL when aggregating hours.
--   4. Không cho phép sửa hours của worklog đã soft-delete (enforce tại backend).
--      Disallow hour updates on soft-deleted worklogs (enforce at backend).
--
-- REPORTING QUERIES / TRUY VẤN BÁO CÁO:
--   Timesheet cá nhân theo tuần:
--     SELECT logged_date, SUM(hours_spent)
--     FROM programming_request_worklogs
--     WHERE created_by = ? AND logged_date BETWEEN ? AND ?
--       AND deleted_at IS NULL
--     GROUP BY logged_date;
--
--   Estimate vs Actual theo phase:
--     SELECT phase, SUM(hours_estimated), SUM(hours_spent)
--     FROM programming_request_worklogs
--     WHERE programming_request_id = ? AND deleted_at IS NULL
--     GROUP BY phase;
-- =====================================================================

CREATE TABLE IF NOT EXISTS `programming_request_worklogs` (
    `id` bigint unsigned NOT NULL AUTO_INCREMENT
         COMMENT 'Auto-increment primary key / Khóa chính tự tăng',

    `programming_request_id` bigint unsigned NOT NULL
                             COMMENT '[FK → programming_requests.id | ON DELETE CASCADE] '
                                     'Yêu cầu lập trình mà worklog này thuộc về. '
                                     'The programming request this worklog entry belongs to. '
                                     'CASCADE: Xóa request thì toàn bộ worklog bị xóa theo. '
                                     'CASCADE: Deleting the request also deletes all its worklogs.',

    `phase` enum('ANALYZE','CODE','UPCODE','NOTIFY','OTHER') NOT NULL DEFAULT 'OTHER'
            COMMENT '[Enum | Required | Default: OTHER] '
                    'Giai đoạn công việc mà worklog này ghi nhận. '
                    'Workflow phase this work session belongs to. '
                    'ANALYZE = Phân tích yêu cầu / Requirement analysis work. '
                    'CODE    = Lập trình, viết code / Development and coding work. '
                    'UPCODE  = Triển khai, deploy lên production / Deployment activities. '
                    'NOTIFY  = Soạn và gửi thông báo cho KH / Notification preparation and sending. '
                    'OTHER   = Họp, review, tài liệu, v.v. / Meetings, reviews, documentation, etc.',

    `content` text NOT NULL
              COMMENT '[Required] Mô tả chi tiết công việc đã thực hiện trong phiên này. '
                      'Detailed description of work performed in this session. '
                      'VD: "Phân tích màn hình Nhập viện, xác nhận rule với KH qua email". '
                      'E.g. "Analyzed Admission screen, confirmed business rules with client via email".',

    `logged_date` date NOT NULL
                  COMMENT '[Required] Ngày thực tế thực hiện công việc (ngày nghiệp vụ). '
                          'Actual date the work was performed (business date). '
                          'KHÔNG PHẢI ngày nhập log vào hệ thống (đó là created_at). '
                          'NOT the date the log was entered (that is created_at). '
                          'Validate tại backend: logged_date <= CURRENT_DATE (không log tương lai). '
                          'Backend validation: logged_date <= CURRENT_DATE (no future logging). '
                          'Laravel rule: "before_or_equal:today".',

-- ----------------------------------------------------------------
-- [FIELD GROUP: Hours — Số giờ]
-- ----------------------------------------------------------------
-- RELATIONSHIP WITH PARENT TABLE / QUAN HỆ VỚI BẢNG CHA:
--   programming_requests.analyze_estimated_hours = Tổng ước tính cả pha (high-level)
--   programming_requests.code_estimated_hours    = Tổng ước tính cả pha (high-level)
--   programming_request_worklogs.hours_estimated = Ước tính cho phiên làm việc CỤ THỂ này
--   programming_request_worklogs.hours_spent     = Thực tế cho phiên làm việc CỤ THỂ này
--
-- Để tính Actual/Estimate tổng hợp cho toàn task, SUM từ bảng worklogs.
-- To get aggregated Actual/Estimate for the full task, SUM from worklogs table.
-- ----------------------------------------------------------------
`hours_estimated` decimal(5, 2) DEFAULT NULL COMMENT 'Số giờ DỰ KIẾN cho công việc trong phiên làm việc cụ thể này. ' 'ESTIMATED hours for work in this specific session. ' 'NULL = không ước tính trước (OK cho log retrospective). ' 'NULL = no upfront estimate (acceptable for retrospective logging). ' 'Phân biệt với analyze_estimated_hours/code_estimated_hours ở bảng cha ' '(đó là ước tính tổng pha, đây là ước tính từng phiên). ' 'Distinguished from parent table phase estimates (those are totals). ' 'Validate tại backend: > 0 AND <= 24 khi không NULL.',
`hours_spent` decimal(5, 2) NOT NULL DEFAULT 0.00 COMMENT '[Required | Default: 0] Số giờ THỰC TẾ đã thực hiện trong phiên này. ' 'ACTUAL hours spent working in this session. ' 'Là dữ liệu cốt lõi của Timesheet — dùng để SUM báo cáo năng suất. ' 'Core Timesheet data — used in SUM aggregations for productivity reporting. ' 'Validate tại backend: > 0 AND <= 24. ' 'Không cho phép sửa trường này khi deleted_at IS NOT NULL (enforce tại backend). ' 'Disallow editing this field when deleted_at IS NOT NULL (backend enforced).',

-- ----------------------------------------------------------------
-- [AUDIT LOG — Nhật ký hệ thống]
-- ----------------------------------------------------------------
`created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Timestamp khi bản ghi được tạo (tự động). ' 'Record creation timestamp (auto-set). ' 'Khác với logged_date là ngày làm việc thực tế. ' 'Different from logged_date which is the actual work date.',
`created_by` bigint unsigned NOT NULL COMMENT '[FK → internal_users.id | ON DELETE RESTRICT | Required] ' 'Nhân viên ghi log này (thường chính là người thực hiện). ' 'Staff who created this log entry (typically the one who did the work). ' 'RESTRICT: Không thể xóa user khi còn worklog do họ tạo. ' 'Cannot delete a user who has worklog records.',
`updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT 'Timestamp cập nhật cuối (tự động). NULL nếu chưa từng sửa. ' 'Last update timestamp (auto-set). NULL if never modified.',
`updated_by` bigint unsigned DEFAULT NULL COMMENT '[FK → internal_users.id | ON DELETE SET NULL] ' 'Nhân viên thực hiện sửa log cuối. NULL nếu chưa từng sửa. ' 'Staff who last modified this entry. NULL if never modified.',
`deleted_at` timestamp NULL DEFAULT NULL COMMENT 'Soft Delete timestamp. NULL = bản ghi đang active. ' 'Soft Delete timestamp. NULL = record is active. ' 'CẢNH BÁO QUAN TRỌNG: Phải thêm WHERE deleted_at IS NULL trong ' 'MỌI truy vấn Aggregate/SUM/COUNT để tránh tính giờ của log đã xóa. ' 'CRITICAL WARNING: Always add WHERE deleted_at IS NULL in ALL ' 'Aggregate/SUM/COUNT queries to exclude hours from deleted logs.',
PRIMARY KEY (`id`),

-- ----------------------------------------------------------------
-- INDEXES — Tối ưu truy vấn Timesheet & Reporting
-- ----------------------------------------------------------------

-- Màn hình Timesheet cá nhân: Ai làm gì vào ngày nào
-- Personal Timesheet screen: Who did what on which day
INDEX `idx_prog_worklog_creator_date` (`created_by`, `logged_date`) COMMENT 'Timesheet cá nhân: lọc log của một nhân viên theo ngày / ' 'Personal Timesheet: filter one staff member logs by date',

-- Lịch sử công việc chi tiết của một yêu cầu theo giai đoạn
-- Detailed work history of one request by phase
INDEX `idx_prog_worklog_req_phase` (
    `programming_request_id`,
    `phase`
) COMMENT 'Lịch sử công việc của task theo giai đoạn / ' 'Work history of a task broken down by phase',

-- Tổng hợp toàn team theo tuần/tháng
-- Team-wide aggregation by week/month
INDEX `idx_prog_worklog_date` (`logged_date`) COMMENT 'Báo cáo tổng hợp toàn team theo khoảng thời gian / ' 'Team-wide report aggregation by time range',

-- Soft-delete filter kết hợp thời gian
-- Soft-delete filter combined with date range
INDEX `idx_prog_worklog_soft_delete` (`deleted_at`, `logged_date`) COMMENT 'Tối ưu kết hợp filter soft-delete và khoảng ngày trong Aggregate / ' 'Optimizes combined soft-delete and date range filter in Aggregate queries',

-- COVERING INDEX: Báo cáo năng suất (Timesheet cá nhân + SUM giờ)
-- deleted_at đứng trước để MySQL loại sớm record đã xóa, tránh table lookup hoàn toàn.
-- COVERING INDEX: Productivity report (personal Timesheet + SUM hours)
-- deleted_at leads so MySQL prunes deleted rows early, eliminating table lookups entirely.
INDEX `idx_prog_worklog_hours_date` (
    `created_by`,
    `deleted_at`,
    `logged_date`,
    `hours_spent`,
    `hours_estimated`
) COMMENT 'COVERING INDEX: SUM(hours_spent), SUM(hours_estimated) theo user/ngày. ' 'Loại trừ table lookup hoàn toàn cho báo cáo năng suất cá nhân. ' 'Eliminates table lookups for personal productivity reports.',

-- COVERING INDEX: Báo cáo Estimate vs Actual theo phase của một task
-- COVERING INDEX: Estimate vs Actual report by phase for one task
INDEX `idx_prog_worklog_phase_hours` (
    `programming_request_id`,
    `deleted_at`,
    `phase`,
    `hours_spent`,
    `hours_estimated`
) COMMENT 'COVERING INDEX: SUM giờ theo pha của một task + soft-delete filter. ' 'Dùng cho báo cáo "Estimate vs Actual" theo từng giai đoạn. ' 'Used for Estimate vs Actual report broken down by phase.',

-- ----------------------------------------------------------------
-- CHECK CONSTRAINTS — Ràng buộc dữ liệu
-- ----------------------------------------------------------------

-- Giờ không được âm (> 0 validate tại backend / > 0 validated at backend)
CONSTRAINT `chk_worklog_hours_spent_non_negative` CHECK (`hours_spent` >= 0),
CONSTRAINT `chk_worklog_hours_estimated_non_negative` CHECK (
    `hours_estimated` IS NULL
    OR `hours_estimated` >= 0
),

-- NOTE: Không có constraint chk_worklog_deleted_has_no_hours ở đây vì:
-- MySQL CHECK không phân biệt thao tác nào đang chạy trên row —
-- nếu có constraint đó, hành động soft-delete (SET deleted_at=NOW()) trên
-- row có hours_spent > 0 sẽ bị từ chối, chặn chính hành động xóa.
-- Thay vào đó: enforce tại backend — từ chối UPDATE hours khi deleted_at IS NOT NULL.
--
-- NOTE: No chk_worklog_deleted_has_no_hours constraint here because:
-- MySQL CHECK cannot distinguish which operation is running on the row —
-- if that constraint existed, soft-deleting (SET deleted_at=NOW()) a row
-- with hours_spent > 0 would be REJECTED, blocking the delete itself.
-- Instead: enforce at backend — reject hour updates when deleted_at IS NOT NULL.
-- Laravel: Policy::update → deny if $worklog->deleted_at !== null.

-- ----------------------------------------------------------------
-- FOREIGN KEYS — Ràng buộc khóa ngoại
-- ----------------------------------------------------------------
CONSTRAINT `fk_prog_worklog_req`
        FOREIGN KEY (`programming_request_id`) REFERENCES `programming_requests`(`id`)
        ON DELETE CASCADE,   -- Xóa request thì xóa toàn bộ worklogs / Delete request = delete all logs

    CONSTRAINT `fk_prog_worklog_cb`
        FOREIGN KEY (`created_by`) REFERENCES `internal_users`(`id`)
        ON DELETE RESTRICT,  -- Không xóa user khi còn worklog / Cannot delete user with worklogs

    CONSTRAINT `fk_prog_worklog_ub`
        FOREIGN KEY (`updated_by`) REFERENCES `internal_users`(`id`)
        ON DELETE SET NULL   -- User bị xóa thì updated_by = NULL / Deleted user sets updated_by to NULL

) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci
  COMMENT='Bảng 41: Nhật ký Công việc / Timesheet cho Yêu cầu Lập trình | '
          'Work session logs for time tracking, Estimate vs Actual reporting';

-- <<< MODULE_APPEND: programming_requests_v12.sql

-- >>> MODULE_APPEND: drop_support_request_legacy_fields_v1
-- Đồng bộ schema mới cho Support Request:
-- 1) Bỏ support_requests.ticket_code
-- 2) Bỏ support_requests.task_link
-- 3) Bỏ support_request_tasks.title (Nội dung task)

SET @sql_drop_idx_support_ticket_code = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.statistics
      WHERE table_schema = DATABASE()
        AND table_name = 'support_requests'
        AND index_name = 'idx_support_ticket_code'
    ),
    'ALTER TABLE `support_requests` DROP INDEX `idx_support_ticket_code`',
    'SELECT 1'
  )
);
PREPARE stmt_drop_idx_support_ticket_code FROM @sql_drop_idx_support_ticket_code;
EXECUTE stmt_drop_idx_support_ticket_code;
DEALLOCATE PREPARE stmt_drop_idx_support_ticket_code;

SET @sql_drop_support_ticket_code = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.columns
      WHERE table_schema = DATABASE()
        AND table_name = 'support_requests'
        AND column_name = 'ticket_code'
    ),
    'ALTER TABLE `support_requests` DROP COLUMN `ticket_code`',
    'SELECT 1'
  )
);
PREPARE stmt_drop_support_ticket_code FROM @sql_drop_support_ticket_code;
EXECUTE stmt_drop_support_ticket_code;
DEALLOCATE PREPARE stmt_drop_support_ticket_code;

SET @sql_drop_support_task_link = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.columns
      WHERE table_schema = DATABASE()
        AND table_name = 'support_requests'
        AND column_name = 'task_link'
    ),
    'ALTER TABLE `support_requests` DROP COLUMN `task_link`',
    'SELECT 1'
  )
);
PREPARE stmt_drop_support_task_link FROM @sql_drop_support_task_link;
EXECUTE stmt_drop_support_task_link;
DEALLOCATE PREPARE stmt_drop_support_task_link;

SET @sql_drop_support_task_title = (
  SELECT IF(
    EXISTS (
      SELECT 1
      FROM information_schema.columns
      WHERE table_schema = DATABASE()
        AND table_name = 'support_request_tasks'
        AND column_name = 'title'
    ),
    'ALTER TABLE `support_request_tasks` DROP COLUMN `title`',
    'SELECT 1'
  )
);
PREPARE stmt_drop_support_task_title FROM @sql_drop_support_task_title;
EXECUTE stmt_drop_support_task_title;
DEALLOCATE PREPARE stmt_drop_support_task_title;

-- <<< MODULE_APPEND: drop_support_request_legacy_fields_v1

-- >>> MODULE_APPEND: support_request_status_transfer_dev_v1
ALTER TABLE `support_request_statuses`
  ADD COLUMN IF NOT EXISTS `is_transfer_dev` TINYINT(1) NOT NULL DEFAULT 0 AFTER `is_terminal`;

UPDATE `support_request_statuses`
SET `is_transfer_dev` = CASE WHEN UPPER(`status_code`) = 'TRANSFER_DEV' THEN 1 ELSE `is_transfer_dev` END,
    `status_name` = CASE WHEN UPPER(`status_code`) = 'TRANSFER_DEV' THEN 'Chuyển Dev' ELSE `status_name` END;
-- <<< MODULE_APPEND: support_request_status_transfer_dev_v1
